function solve(n) {
    // Helper function for calculating cube
    const cube = (k) => k * k * k;

    // Map to store sum (x) -> count of distinct pairs (a, b) that generate it.
    const sums = new Map();

    // Determine the maximum possible value for b such that b^3 <= n.
    // Since n <= 10^9, Math.cbrt is reliable.
    let B_limit = Math.floor(Math.cbrt(n));

    // Iterate through all possible pairs (a, b) such that 1 <= a <= b and a^3 + b^3 <= n.
    for (let b = 1; b <= B_limit; b++) {
        const b3 = cube(b);

        // Iterate a from 1 up to b.
        for (let a = 1; a <= b; a++) {
            const a3 = cube(a);

            const x = a3 + b3;

            if (x > n) {
                // Since a is increasing, further pairs for this b will exceed n.
                break; 
            }

            // Update count for x.
            sums.set(x, (sums.get(x) || 0) + 1);
        }
    }

    const goodNumbers = [];

    // Collect sums that occurred at least twice.
    for (const [x, count] of sums.entries()) {
        if (count >= 2) {
            goodNumbers.push(x);
        }
    }

    // Return the results sorted in ascending order.
    goodNumbers.sort((a, b) => a - b);

    return goodNumbers;
}

